import { execFileSync } from "node:child_process";
import { readFileSync, writeFileSync } from "node:fs";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const sourcePath = resolve(root, "content", "about-devhub.md");
const outPath = resolve(root, "src", "lib", "about-devhub-generated.ts");

const raw = readFileSync(sourcePath, "utf-8");
const banner =
  "// Generated by scripts/emit-about-devhub.mjs from content/about-devhub.md. Do not edit by hand.\n\n";
const body = `${banner}export const ABOUT_DEVHUB_MARKDOWN_BODY = ${JSON.stringify(raw)};\n`;

writeFileSync(outPath, body, "utf-8");
execFileSync("npx", ["prettier", "-w", outPath], {
  cwd: root,
  stdio: "inherit",
});
